@spec gm_shift_out_spec  src=tests/specs/gm_shift_out_spec.lua  loc=107  sha=1747f65  cases=2
@exercises midiManager (h.fm), groupManager (h.gm), trackerView (h.vm), editCursor (h.ec), trackerManager (h.tm), commandManager (h.cmgr)
@surface   fm:notes, gm:markGroup, vm:eventsInRect, vm:selectionAsRect, ec:selClear, gm:newInstance, tm:flush, ec:setPos, cmgr:invoke, gm:setLocalMode, gm:assignEvent
@harness   mk{seed.notes}

# Intent
  Repro: eventShiftLeft/Right on a group member. Moving a member sideways
  is a pattern edit (design/group-aware-editing.md decision 1). Shifting a
  member OUT of its region must leave one note total (synced) or one
  standalone + untouched siblings (overridden) -- never a duplicate.

# Helpers
  @fn noteCol(h, chan, lane)  @ 8-13
  @fn allNotes(h)  @ 15-29
  @fn noteAt(notes, chan, ppq)  @ 31-35
  @fn rowOfPpq(h, colIx, ppq)  @ 38-42
      -- The grid row of the cell at colIx with the given ppq (ppq/row is not fixed).
  @fn setup(harness)  @ 44-54

# Cases
  @case 'shift a synced sibling out: one note total, member leaves the pattern'  [harness]  @ 58-72
  @case 'shift an overridden member out: override peels to reveal the synced note, standalone at dest'  [harness]  @ 75-105

# Uses (outbound edges)
  @use call fm:notes  @ 17
  @use call gm:markGroup  @ 51
  @use call vm:eventsInRect  @ 51
  @use call vm:selectionAsRect  @ 51
  @use call ec:selClear  @ 52
  @use call gm:newInstance  @ 61,78
  @use call tm:flush  @ 62,79,83
  @use call ec:setPos  @ 63,86
  @use call cmgr:invoke  @ 64,87
